using Microsoft.EntityFrameworkCore;
class ProductContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Product>(entity =>
        {
            entity.ToContainer("Products");

            // EF Core 9 changed the default discriminator property from "Discriminator" to "$type".
            // Preserve "Discriminator" so existing 500K documents and direct SQL queries
            // (e.g. c.Discriminator = 'Product') continue to work without a data migration.
            entity.HasDiscriminator<string>("Discriminator");

            // EF Core 9 changed id generation from "EntityType|Key" to just "Key".
            // Preserve the old composite format so FindAsync and point-reads
            // still resolve existing documents whose ids are "Product|123".
            entity.HasRootDiscriminatorInJsonId(true);
        });

        // REMOVED: HasIndex(p => p.Sku)
        // EF Core 9 Cosmos provider now throws on HasIndex — Cosmos DB indexing
        // must be managed via the container's indexing policy (Azure Portal / Bicep / Terraform).
    }
}
class Product { public int Id { get; set; } public string Sku { get; set; } }

